  1→import { useSources } from "@/features/sources/context/SourcesContext";
  2→import type { SourceId } from "@/lib/types/primitives";
  3→import { LiquidGlassInput, LiquidGlassSelect } from "@/modules/liquid-glass";
  4→import { useTranslation } from "@/platform/i18n/useTranslation";
  5→import { getGlassInputColors } from "@/platform/theme/glassStyles";
  6→import { useTheme, type Theme } from "@/platform/theme/useTheme";
  7→import { Picker } from "@react-native-picker/picker";
  8→import {
  9→  forwardRef,
 10→  useCallback,
 11→  useEffect,
 12→  useImperativeHandle,
 13→  useState,
 14→  type JSX,
 15→} from "react";
 16→import {
 17→  Modal,
 18→  Platform,
 19→  Pressable,
 20→  StyleSheet,
 21→  View,
 22→} from "react-native";
 23→
 24→const ADD_NEW_VALUE = "__ADD_NEW__";
 25→
 26→export interface SourceSelectorRef {
 27→  confirmNewSource: () => Promise<SourceId | undefined>;
 28→  cancelEdit: () => boolean;
 29→}
 30→
 31→export const SourceSelector = forwardRef<
 32→  SourceSelectorRef,
 33→  {
 34→    value: SourceId;
 35→    onValueChange: (sourceId: SourceId, isAutomatic?: boolean) => void;
 36→    onInteraction?: () => void;
 37→    onEditingChange?: (editing: boolean) => void;
 38→    onHasNoSourcesChange?: (hasNoSources: boolean) => void;
 39→  }
 40→>(function SourceSelector(
 41→  { value, onValueChange, onInteraction, onEditingChange, onHasNoSourcesChange },
 42→  ref
 43→): JSX.Element {
 44→  const { t } = useTranslation();
 45→  const theme = useTheme();
 46→  const { sources, createSource, getLastUsed } = useSources();
 47→
 48→  const [isEditingNewSource, setIsEditingNewSource] = useState(false);
 49→  const [pickerModalVisible, setPickerModalVisible] = useState(false);
 50→  const [newSourceText, setNewSourceText] = useState("");
 51→  const [tempValue, setTempValue] = useState(value);
 52→
 53→  const hasNoSources = sources.length === 0;
 54→
 55→  useEffect(() => {
 56→    onHasNoSourcesChange?.(hasNoSources);
 57→  }, [hasNoSources, onHasNoSourcesChange]);
 58→
 59→  useEffect(() => {
 60→    if (!value) {
 61→      const lastUsed = getLastUsed();
 62→      if (lastUsed) {
 63→        onValueChange(lastUsed.id, true);
 64→      }
 65→    }
 66→  }, [getLastUsed, value, onValueChange]);
 67→
 68→  // Sync tempValue when value changes externally
 69→  useEffect(() => {
 70→    setTempValue(value);
 71→  }, [value]);
 72→
 73→  const selectedSourceName = sources.find((s) => s.id === value)?.name ?? "";
 74→
 75→  const openPickerModal = useCallback(() => {
 76→    setTempValue(value || (sources.length > 0 ? sources[0].id : ""));
 77→    setPickerModalVisible(true);
 78→    onInteraction?.();
 79→  }, [value, sources, onInteraction]);
 80→
 81→  const handleNativePickerChange = useCallback(
 82→    (itemValue: string) => {
 83→      setTempValue(itemValue);
 84→      setPickerModalVisible(false);
 85→      if (itemValue === ADD_NEW_VALUE) {
 86→        setIsEditingNewSource(true);
 87→      } else if (itemValue) {
 88→        onValueChange(itemValue, false);
 89→      }
 90→    },
 91→    [onValueChange]
 92→  );
 93→
 94→  const handlePickerClose = useCallback(() => {
 95→    setPickerModalVisible(false);
 96→    setTempValue(value);
 97→  }, [value]);
 98→
 99→  const handleConfirmNewSource = useCallback(async (): Promise<
100→    SourceId | undefined
101→  > => {
102→    const trimmedSource = newSourceText.trim();
103→    if (!trimmedSource) {
104→      return undefined;
105→    }
106→
107→    const newSource = await createSource(trimmedSource);
108→    onValueChange(newSource.id, false);
109→    setIsEditingNewSource(false);
110→    setNewSourceText("");
111→    return newSource.id;
112→  }, [newSourceText, createSource, onValueChange]);
113→
114→  const handleCancelEdit = useCallback<() => boolean>((): boolean => {
115→    const wasEditing = isEditingNewSource;
116→    if (wasEditing) {
117→      setIsEditingNewSource(false);
118→    }
119→    setNewSourceText("");
120→    return wasEditing;
121→  }, [isEditingNewSource]);
122→
123→  useEffect(() => {
124→    onEditingChange?.(isEditingNewSource || hasNoSources);
125→  }, [isEditingNewSource, hasNoSources, onEditingChange]);
126→
127→  useImperativeHandle(
128→    ref,
129→    () => ({
130→      confirmNewSource: handleConfirmNewSource,
131→      cancelEdit: handleCancelEdit,
132→    }),
133→    [handleConfirmNewSource, handleCancelEdit]
134→  );
135→
136→  const handleWebPickerChange = useCallback(
137→    (itemValue: string) => {
138→      if (itemValue === ADD_NEW_VALUE) {
139→        setIsEditingNewSource(true);
140→        onInteraction?.();
141→      } else if (itemValue) {
142→        onValueChange(itemValue, false);
143→        onInteraction?.();
144→      }
145→    },
146→    [onValueChange, onInteraction]
147→  );
148→
149→  const isWeb = Platform.OS === "web";
150→  const themeColors = getThemeColors(theme);
151→
152→  return (
153→    <>
154→      <View style={styles.container}>
155→        {isWeb ? (
156→          <Picker
157→            selectedValue={value || ""}
158→            onValueChange={handleWebPickerChange}
159→            style={[styles.triggerButton, themeColors.triggerButton]}
160→          >
161→            {!value && (
162→              <Picker.Item
163→                label={t("sourceSelector.placeholder")}
164→                value=""
165→                enabled={false}
166→              />
167→            )}
168→            {sources.map((source) => (
169→              <Picker.Item
170→                key={source.id}
171→                label={source.name}
172→                value={source.id}
173→              />
174→            ))}
175→            <Picker.Item
176→              label={t("sourceSelector.addNew")}
177→              value={ADD_NEW_VALUE}
178→            />
179→          </Picker>
180→        ) : hasNoSources || isEditingNewSource ? (
181→          <LiquidGlassInput
182→            value={newSourceText}
183→            onChangeText={setNewSourceText}
184→            placeholder={t("sourceSelector.addNewPlaceholder")}
185→            variant="text"
186→            autoFocus
187→            maxLength={100}
188→            returnKeyType="done"
189→            onSubmitEditing={handleConfirmNewSource}
190→            style={styles.glassSelect}
191→          />
192→        ) : (
193→          <LiquidGlassSelect
194→            value={selectedSourceName}
195→            placeholder={t("sourceSelector.placeholder")}
196→            onPress={openPickerModal}
197→            style={styles.glassSelect}
198→          />
199→        )}
200→      </View>
201→
202→      {/* Picker Modal - shows full-height native iOS picker wheel */}
203→      <Modal
204→        visible={pickerModalVisible}
205→        transparent
206→        animationType="slide"
207→        onRequestClose={handlePickerClose}
208→      >
209→        <View style={styles.pickerModalOverlay}>
210→          <Pressable
211→            style={styles.pickerModalBackdrop}
212→            onPress={handlePickerClose}
213→          />
214→          <View
215→            style={[
216→              styles.pickerModalContent,
217→              {
218→                backgroundColor:
219→                  theme === "dark"
220→                    ? "rgba(44, 44, 46, 1)"
221→                    : "rgba(255, 255, 255, 1)",
222→              },
223→            ]}
224→          >
225→            <Picker
226→              selectedValue={tempValue}
227→              onValueChange={handleNativePickerChange}
228→              style={styles.pickerWheel}
229→              itemStyle={themeColors.pickerItem}
230→            >
231→              {sources.map((source) => (
232→                <Picker.Item
233→                  key={source.id}
234→                  label={source.name}
235→                  value={source.id}
236→                />
237→              ))}
238→              <Picker.Item
239→                label={t("sourceSelector.addNew")}
240→                value={ADD_NEW_VALUE}
241→              />
242→            </Picker>
243→          </View>
244→        </View>
245→      </Modal>
246→    </>
247→  );
248→});
249→
250→function getThemeColors(theme: Theme) {
251→  const isDark = theme === "dark";
252→  const inputColors = getGlassInputColors(theme);
253→
254→  return {
255→    label: inputColors.label,
256→    text: inputColors.text,
257→    input: {
258→      backgroundColor: "transparent",
259→      borderColor: isDark ? "rgba(255, 255, 255, 0.2)" : "rgba(0, 0, 0, 0.1)",
260→      color: isDark ? "rgba(255, 255, 255, 0.5)" : "#000000",
261→    },
262→    triggerButton: {
263→      backgroundColor: isDark
264→        ? "rgba(255, 255, 255, 0.1)"
265→        : "rgba(0, 0, 0, 0.05)",
266→      borderColor: isDark ? "rgba(255, 255, 255, 0.2)" : "rgba(0, 0, 0, 0.1)",
267→    },
268→    pickerItem: {
269→      color: isDark ? "#FFFFFF" : "#000000",
270→      fontSize: 20,
271→    },
272→    placeholder: inputColors.placeholder,
273→  };
274→}
275→
276→const styles = StyleSheet.create({
277→  container: {
278→    flexGrow: 1,
279→    flexShrink: 0,
280→  },
281→  glassSelect: {
282→    height: 48,
283→  },
284→  triggerButton: {
285→    height: 48,
286→    paddingHorizontal: 16,
287→    flexDirection: "row",
288→    alignItems: "center",
289→    justifyContent: "space-between",
290→  },
291→  pickerModalOverlay: {
292→    flex: 1,
293→    justifyContent: "flex-end",
294→  },
295→  pickerModalBackdrop: {
296→    ...StyleSheet.absoluteFillObject,
297→    backgroundColor: "rgba(0, 0, 0, 0.4)",
298→  },
299→  pickerModalContent: {
300→    borderTopLeftRadius: 12,
301→    borderTopRightRadius: 12,
302→    overflow: "hidden",
303→  },
304→  pickerWheel: {
305→    height: 216,
306→  },
307→});
