 1→import { LiquidGlassButton } from "@/modules/liquid-glass";
 2→import { useCallback, type JSX } from "react";
 3→
 4→export function ConfirmButton({
 5→  onConfirm,
 6→  disabled = false,
 7→  loading = false,
 8→}: {
 9→  onConfirm: () => void;
10→  disabled?: boolean;
11→  loading?: boolean;
12→}): JSX.Element {
13→  const handlePress = useCallback(() => {
14→    if (disabled || loading) return;
15→    onConfirm();
16→  }, [disabled, loading, onConfirm]);
17→
18→  return (
19→    <LiquidGlassButton
20→      onPress={handlePress}
21→      systemImage="checkmark"
22→      size={48}
23→      loading={loading}
24→    />
25→  );
26→}
