  1→import { ConfirmButton } from "@/features/recipe-import/components/ConfirmButton";
  2→import {
  3→  SourceSelector,
  4→  type SourceSelectorRef,
  5→} from "@/features/source-selector/components/SourceSelector";
  6→import { Alert } from "@/lib/alert";
  7→import type { PhotoUri, SourceId } from "@/lib/types/primitives";
  8→import { LiquidGlassButton } from "@/modules/liquid-glass";
  9→import { useTranslation } from "@/platform/i18n/useTranslation";
 10→import { useTheme, type Theme } from "@/platform/theme/useTheme";
 11→import * as Haptics from "expo-haptics";
 12→import { Image } from "expo-image";
 13→import { router } from "expo-router";
 14→import { useCallback, useRef, useState, type JSX } from "react";
 15→import { KeyboardAvoidingView, Platform, StyleSheet, View } from "react-native";
 16→
 17→export function AddRecipeForm({
 18→  photoUri,
 19→  source,
 20→  onSourceChange,
 21→  onConfirm,
 22→}: {
 23→  photoUri: PhotoUri;
 24→  source: SourceId;
 25→  onSourceChange: (sourceId: SourceId, isAutomatic?: boolean) => void;
 26→  onConfirm: (sourceOverride?: SourceId) => void;
 27→}): JSX.Element {
 28→  const theme = useTheme();
 29→  const { t } = useTranslation();
 30→  const sourceSelectorRef = useRef<SourceSelectorRef>(null);
 31→  const [isEditingSource, setIsEditingSource] = useState(false);
 32→  const [isConfirming, setIsConfirming] = useState(false);
 33→
 34→  const handleEditingChange = useCallback((editing: boolean) => {
 35→    setIsEditingSource(editing);
 36→  }, []);
 37→
 38→  const handleClose = useCallback(() => {
 39→    if (isConfirming) return;
 40→    if (isEditingSource) {
 41→      const cancelled = sourceSelectorRef.current?.cancelEdit();
 42→      if (cancelled) return;
 43→    }
 44→    if (Platform.OS !== "web") {
 45→      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
 46→    }
 47→    Alert.alert(
 48→      t("recipeForm.discardChanges.title"),
 49→      t("recipeForm.discardChanges.message"),
 50→      [
 51→        { text: t("recipeForm.discardChanges.cancel"), style: "cancel" },
 52→        {
 53→          text: t("recipeForm.discardChanges.discard"),
 54→          style: "destructive",
 55→          onPress: () => {
 56→            if (Platform.OS !== "web") {
 57→              Haptics.notificationAsync(
 58→                Haptics.NotificationFeedbackType.Warning
 59→              );
 60→            }
 61→            router.back();
 62→          },
 63→        },
 64→      ]
 65→    );
 66→  }, [isConfirming, isEditingSource, t]);
 67→
 68→  const handleConfirm = useCallback(async () => {
 69→    if (isConfirming) return;
 70→    if (isEditingSource) {
 71→      const confirmed = await sourceSelectorRef.current?.confirmNewSource();
 72→      if (!confirmed) return;
 73→      setIsConfirming(true);
 74→      onConfirm(confirmed);
 75→      return;
 76→    }
 77→    if (!source) return;
 78→    setIsConfirming(true);
 79→    onConfirm();
 80→  }, [isConfirming, isEditingSource, source, onConfirm]);
 81→
 82→  return (
 83→    <KeyboardAvoidingView
 84→      style={[styles.container, getThemeColors(theme).container]}
 85→      behavior={Platform.OS === "ios" ? "padding" : "height"}
 86→    >
 87→      <View style={styles.processingContainer}>
 88→        <Image
 89→          source={{ uri: photoUri }}
 90→          style={styles.processingImage}
 91→          contentFit="cover"
 92→        />
 93→        <View style={styles.processingBottomBar}>
 94→          <LiquidGlassButton
 95→            disabled={isConfirming}
 96→            onPress={handleClose}
 97→            accessibilityLabel={t("accessibility.close")}
 98→            systemImage="xmark"
 99→          />
100→          <View
101→            pointerEvents={isConfirming ? "none" : "auto"}
102→            style={[styles.sourceSelectorWrapper, isConfirming && styles.disabled]}
103→          >
104→            <SourceSelector
105→              ref={sourceSelectorRef}
106→              value={source}
107→              onValueChange={onSourceChange}
108→              onEditingChange={handleEditingChange}
109→            />
110→          </View>
111→          <ConfirmButton
112→            onConfirm={handleConfirm}
113→            disabled={!isEditingSource && !source}
114→            loading={isConfirming}
115→          />
116→        </View>
117→      </View>
118→    </KeyboardAvoidingView>
119→  );
120→}
121→
122→function getThemeColors(theme: Theme) {
123→  const isDark = theme === "dark";
124→
125→  return {
126→    container: {
127→      backgroundColor: isDark ? "#000000" : "#FFFFFF",
128→    },
129→  };
130→}
