 1→import { useBackgroundProcessing } from "@/features/background-processing";
 2→import { AddRecipeForm } from "@/features/recipe-form/components/AddRecipeForm";
 3→import { useRecipes } from "@/features/recipes-list/context/RecipesContext";
 4→import { useSources } from "@/features/sources/context/SourcesContext";
 5→import type { PhotoUri, SourceId } from "@/lib/types/primitives";
 6→import { useTheme, type Theme } from "@/platform/theme/useTheme";
 7→import { router, useLocalSearchParams } from "expo-router";
 8→import { useCallback, useState, type JSX } from "react";
 9→import { StyleSheet } from "react-native";
10→import { SafeAreaView } from "react-native-safe-area-context";
11→
12→export default function AddRecipeScreen(): JSX.Element {
13→  const theme = useTheme();
14→  const { uri } = useLocalSearchParams<{ uri: PhotoUri }>();
15→  const { touchSource, getLastUsed } = useSources();
16→  const [source, setSource] = useState<SourceId>(() => {
17→    const lastUsed = getLastUsed();
18→    return lastUsed ? lastUsed.id : "";
19→  });
20→  const { savePending } = useRecipes();
21→  const { addToQueue } = useBackgroundProcessing();
22→
23→  const handleConfirm = useCallback(
24→    async (sourceOverride?: SourceId) => {
25→      const effectiveSource = sourceOverride ?? source;
26→      if (!uri || !effectiveSource) {
27→        return;
28→      }
29→
30→      const recipe = await savePending(uri, effectiveSource);
31→      addToQueue(recipe.id);
32→      router.back();
33→      touchSource(effectiveSource);
34→    },
35→    [uri, source, savePending, touchSource, addToQueue]
36→  );
37→
38→  if (!uri) {
39→    return (
40→      <SafeAreaView
41→        edges={["top", "left", "right"]}
42→        style={[styles.container, getThemeColors(theme).container]}
43→      />
44→    );
45→  }
46→
47→  return (
48→    <SafeAreaView
49→      edges={["top", "left", "right"]}
50→      style={[styles.container, getThemeColors(theme).container]}
51→    >
52→      <AddRecipeForm
53→        photoUri={uri}
54→        source={source}
55→        onSourceChange={setSource}
56→        onConfirm={handleConfirm}
57→      />
58→    </SafeAreaView>
59→  );
60→}
61→
62→function getThemeColors(theme: Theme) {
63→  const isDark = theme === "dark";
64→
65→  return {
66→    container: {
67→      backgroundColor: isDark ? "#000000" : "#FFFFFF",
68→    },
69→  };
70→}
71→
72→const styles = StyleSheet.create({
73→  container: {
74→    flex: 1,
75→  },
76→});
