  1→import { router } from "expo-router";
  2→import { LiquidGlassButton, LiquidGlassPopover } from "liquid-glass";
  3→import { Suspense, useCallback, useEffect, useMemo, type JSX } from "react";
  4→import { ErrorBoundary } from "react-error-boundary";
  5→import {
  6→  Keyboard,
  7→  KeyboardAvoidingView,
  8→  Platform,
  9→  Pressable,
 10→  StyleSheet,
 11→  Text,
 12→  View,
 13→} from "react-native";
 14→import Animated from "react-native-reanimated";
 15→import { useSafeAreaInsets } from "react-native-safe-area-context";
 16→import { useDebugContext } from "../features/photo-adjustment/context/DebugContext";
 17→import { EmptyState } from "../features/photos/components/EmptyState";
 18→import { useImportPopover } from "../features/photos/hooks/useImportPopover";
 19→import { usePopoverTransition } from "../features/photos/hooks/usePopoverTransition";
 20→import { AddRecipeButton } from "../features/recipe-form/components/AddRecipeButton";
 21→import { RecipeGrid } from "../features/recipes-list/components/RecipeGrid";
 22→import { useRecipes } from "../features/recipes-list/context/RecipesContext";
 23→import { useGlobalOptions } from "../features/recipes-list/hooks/useGlobalOptions";
 24→import { filterRecipesWithQuery } from "../features/recipes-list/utils/recipeSearch";
 25→import { SearchBar } from "../features/search/components/SearchBar";
 26→import { useAddButtonFocusTransition } from "../features/search/hooks/useAddButtonFocusTransition";
 27→import { useSearchQuery } from "../features/search/hooks/useSearchQuery";
 28→import { useSearchFocus } from "../features/search/hooks/useSearchFocus";
 29→import { useTags } from "../features/tags/context/TagsContext";
 30→import type { RecipeId } from "../lib/types/primitives";
 31→import { useTranslation } from "../platform/i18n/useTranslation";
 32→import { getColors } from "../platform/theme/glassStyles";
 33→import { useTheme } from "../platform/theme/useTheme";
 34→
 35→const HEADER_TOP_GAP = 8;
 36→// NOTE: 61 makes the gap above the three global menu button equal to the gap below
 37→const HEADER_ROW_HEIGHT = 61;
 38→const HEADER_BOTTOM_GAP = 8;
 39→const HEADER_AREA_HEIGHT = HEADER_TOP_GAP + HEADER_ROW_HEIGHT + HEADER_BOTTOM_GAP;
 40→
 41→function ErrorFallback({ error }: { error?: Error }): JSX.Element {
 42→  return (
 43→    <View style={styles.errorContainer}>
 44→      <Text style={styles.errorTitle}>Error loading recipes</Text>
 45→      {error && <Text style={styles.errorMessage}>{error.message}</Text>}
 46→    </View>
 47→  );
 48→}
 49→
 50→function Content(): JSX.Element {
 51→  const theme = useTheme();
 52→  const colors = getColors(theme);
 53→  const { t } = useTranslation();
 54→  const insets = useSafeAreaInsets();
 55→  const { recipes } = useRecipes();
 56→  const { tags, tagLookup } = useTags();
 57→  const {
 58→    query,
 59→    addTagFromSuggestion,
 60→    removeSelectedTag,
 61→    setFreeText,
 62→    clearQuery,
 63→  } = useSearchQuery();
 64→  const filteredRecipes = useMemo(() => {
 65→    return filterRecipesWithQuery(recipes, query, tagLookup);
 66→  }, [recipes, query, tagLookup]);
 67→  const { handleFocus, handleBlur, key, isFocused } = useSearchFocus();
 68→  const { setDebugData } = useDebugContext();
 69→
 70→  const {
 71→    showPopover,
 72→    popoverVisible,
 73→    dismissPopover,
 74→    isImporting,
 75→    importOptions,
 76→    handleImportOptionSelect,
 77→  } = useImportPopover();
 78→  const shouldHideSearchBar = popoverVisible || isImporting;
 79→  const { buttonStyle } = usePopoverTransition(shouldHideSearchBar);
 80→
 81→  const globalOptions = useGlobalOptions();
 82→  const { addButtonOuterStyle, addButtonInnerStyle } =
 83→    useAddButtonFocusTransition(isFocused);
 84→
 85→  useEffect(() => {
 86→    return () => {
 87→      setDebugData(null);
 88→    };
 89→  }, [setDebugData]);
 90→
 91→  const isAddButtonInteractive = !isFocused && !popoverVisible && !isImporting;
 92→
 93→  const dismissSearchFocus = useCallback((): void => {
 94→    if (!isFocused) {
 95→      return;
 96→    }
 97→
 98→    handleBlur();
 99→    Keyboard.dismiss();
100→  }, [handleBlur, isFocused]);
101→
102→  const handleRecipeTap = useCallback(
103→    (id: RecipeId): void => {
104→      dismissSearchFocus();
105→      router.push(`/recipe/${id}`);
106→    },
107→    [dismissSearchFocus]
108→  );
109→
110→  const handleGlobalMenuPress = useCallback((): void => {
111→    dismissSearchFocus();
112→    globalOptions.handlePress();
113→  }, [dismissSearchFocus, globalOptions]);
114→
115→  return (
116→    <View style={[styles.container, { backgroundColor: colors.background }]}>
117→      {recipes.length === 0 ? (
118→        <Pressable style={styles.container} onPress={dismissSearchFocus}>
119→          <EmptyState onAddPress={showPopover} hiding={shouldHideSearchBar} />
120→        </Pressable>
121→      ) : (
122→        <RecipeGrid
123→          recipes={filteredRecipes}
124→          onRecipeTap={handleRecipeTap}
