 1→import type { ViewStyle } from "react-native";
 2→
 3→export type LiquidGlassPopoverOption = {
 4→  id: string;
 5→  label: string;
 6→  systemImage: string;
 7→};
 8→
 9→export type LiquidGlassPopoverProps = {
10→  visible: boolean;
11→  options: Array<LiquidGlassPopoverOption>;
12→  onSelect: (id: string) => void;
13→  onDismiss: () => void;
14→  buttonSize?: number;
15→  style?: ViewStyle;
16→  anchor?: "bottomTrailing" | "topTrailing" | "center";
17→  buttonOffset?: { x: number; y: number };
18→};
