 1→import { type JSX } from "react";
 2→import { Modal, Pressable, StyleSheet, Text, View } from "react-native";
 3→import type { LiquidGlassPopoverProps } from "./LiquidGlassPopover.types";
 4→
 5→const DEFAULT_OFFSET = { x: 28, y: 28 };
 6→
 7→export function LiquidGlassPopover({
 8→  visible,
 9→  options,
10→  onSelect,
11→  onDismiss,
12→  anchor = "bottomTrailing",
13→  buttonOffset,
14→}: LiquidGlassPopoverProps): JSX.Element | null {
15→  if (!visible) {
16→    return null;
17→  }
18→
19→  const offset = buttonOffset ?? DEFAULT_OFFSET;
20→
21→  const anchorStyle =
22→    anchor === "center"
23→      ? ({
24→          justifyContent: "center",
25→          alignItems: "center",
26→        } as const)
27→      : anchor === "topTrailing"
28→        ? ({
29→            justifyContent: "flex-start",
30→            alignItems: "flex-end",
31→            paddingTop: offset.y,
32→            paddingRight: offset.x,
33→          } as const)
34→        : ({
35→            justifyContent: "flex-end",
36→            alignItems: "flex-end",
37→            paddingBottom: offset.y,
38→            paddingRight: offset.x,
39→          } as const);
40→
41→  return (
42→    <Modal visible transparent animationType="fade" onRequestClose={onDismiss}>
43→      <Pressable style={[styles.backdrop, anchorStyle]} onPress={onDismiss}>
44→        <View style={styles.menu}>
45→          {options.map((option) => (
46→            <Pressable
47→              key={option.id}
48→              style={styles.option}
49→              onPress={() => onSelect(option.id)}
50→            >
51→              <Text style={styles.optionText}>{option.label}</Text>
52→            </Pressable>
53→          ))}
54→        </View>
55→      </Pressable>
56→    </Modal>
57→  );
58→}
59→
