62→    flex: 1,
63→    backgroundColor: "rgba(0, 0, 0, 0.3)",
64→  },
65→  menu: {
66→    backgroundColor: "#fff",
67→    borderRadius: 12,
68→    minWidth: 200,
69→    overflow: "hidden",
70→  },
71→  option: {
72→    paddingVertical: 12,
73→    paddingHorizontal: 16,
74→    borderBottomWidth: StyleSheet.hairlineWidth,
75→    borderBottomColor: "rgba(0, 0, 0, 0.1)",
76→  },
77→  optionText: {
78→    fontSize: 17,
79→  },
80→});
