  1→import SwiftUI
  2→import ExpoModulesCore
  3→
  4→struct PopoverOption: Identifiable {
  5→  let id: String
  6→  let label: String
  7→  let systemImage: String
  8→}
  9→
 10→public final class LiquidGlassPopoverView: ExpoView {
 11→  private let hostingController: UIHostingController<LiquidGlassPopoverContent>
 12→  
 13→  private var isVisible: Bool = false
 14→  private var options: [PopoverOption] = []
 15→  private var buttonSize: CGFloat = 48
 16→  private var anchor: String = "bottomTrailing"
 17→  private var buttonOffsetX: CGFloat = 28
 18→  private var buttonOffsetY: CGFloat = 28
 19→  let onOptionSelect = EventDispatcher()
 20→  let onDismiss = EventDispatcher()
 21→  
 22→  public required init(appContext: AppContext? = nil) {
 23→    let content = LiquidGlassPopoverContent(
 24→      isVisible: false,
 25→      options: [],
 26→      buttonSize: 48,
 27→      anchor: "bottomTrailing",
 28→      buttonOffsetX: 28,
 29→      buttonOffsetY: 28,
 30→      onOptionSelect: { _ in },
 31→      onDismiss: { }
 32→    )
 33→    
 34→    hostingController = UIHostingController(rootView: content)
 35→    hostingController.view.backgroundColor = .clear
 36→
 37→    // Disable safe area and layout margin handling to prevent content offset
 38→    if #available(iOS 16.4, *) {
 39→      hostingController.safeAreaRegions = []
 40→    }
 41→    hostingController.view.insetsLayoutMarginsFromSafeArea = false
 42→    hostingController.view.layoutMargins = .zero
 43→    hostingController.view.directionalLayoutMargins = .zero
 44→
 45→    super.init(appContext: appContext)
 46→    
 47→    addSubview(hostingController.view)
 48→    clipsToBounds = false
 49→    hostingController.view.clipsToBounds = false
 50→    hostingController.view.preservesSuperviewLayoutMargins = false
 51→    
 52→    updateContent()
 53→  }
 54→  
 55→  public override func layoutSubviews() {
 56→    super.layoutSubviews()
 57→    hostingController.view.frame = bounds
 58→  }
 59→  
 60→  public override func didMoveToWindow() {
 61→    super.didMoveToWindow()
 62→    if window != nil {
 63→      if let parentVC = findViewController() {
 64→        parentVC.addChild(hostingController)
 65→        hostingController.didMove(toParent: parentVC)
 66→      }
 67→    } else {
 68→      hostingController.willMove(toParent: nil)
 69→      hostingController.removeFromParent()
 70→    }
 71→  }
 72→  
 73→  private func findViewController() -> UIViewController? {
 74→    var responder: UIResponder? = self
 75→    while let nextResponder = responder?.next {
 76→      if let viewController = nextResponder as? UIViewController {
 77→        return viewController
 78→      }
 79→      responder = nextResponder
 80→    }
 81→    return nil
 82→  }
 83→  
 84→  func setVisible(_ visible: Bool) {
 85→    isVisible = visible
 86→    updateContent()
 87→  }
 88→  
 89→  func setButtonSize(_ size: CGFloat) {
 90→    buttonSize = size
 91→    updateContent()
 92→  }
 93→
 94→  func setAnchor(_ value: String) {
 95→    anchor = value
 96→    updateContent()
 97→  }
 98→
 99→  func setButtonOffset(_ offset: [String: CGFloat]) {
100→    buttonOffsetX = offset["x"] ?? 28
101→    buttonOffsetY = offset["y"] ?? 28
102→    updateContent()
103→  }
104→
105→  func setOptions(_ optionsData: [[String: Any]]) {
106→    options = optionsData.compactMap { dict in
107→      guard let id = dict["id"] as? String,
108→            let label = dict["label"] as? String,
109→            let systemImage = dict["systemImage"] as? String else {
110→        return nil
111→      }
112→      return PopoverOption(id: id, label: label, systemImage: systemImage)
113→    }
114→    updateContent()
115→  }
116→  
117→  private func updateContent() {
118→    let content = LiquidGlassPopoverContent(
119→      isVisible: isVisible,
120→      options: options,
121→      buttonSize: buttonSize,
122→      anchor: anchor,
123→      buttonOffsetX: buttonOffsetX,
124→      buttonOffsetY: buttonOffsetY,
125→      onOptionSelect: { [weak self] optionId in
126→        self?.onOptionSelect(["id": optionId])
127→      },
128→      onDismiss: { [weak self] in
129→        self?.onDismiss()
130→      }
131→    )
132→    hostingController.rootView = content
133→  }
134→}
135→
136→struct HighlightButtonStyle: ButtonStyle {
137→  func makeBody(configuration: Configuration) -> some View {
138→    configuration.label
139→      .opacity(configuration.isPressed ? 0.5 : 1.0)
140→      .animation(.easeInOut(duration: 0.1), value: configuration.isPressed)
141→  }
142→}
143→
144→struct LiquidGlassPopoverContent: View {
145→  var isVisible: Bool
146→  var options: [PopoverOption]
147→  var buttonSize: CGFloat
148→  var anchor: String
149→  var buttonOffsetX: CGFloat
150→  var buttonOffsetY: CGFloat
151→  var onOptionSelect: (String) -> Void
152→  var onDismiss: () -> Void
153→
154→  @State private var expanded = false
155→  @State private var shrinkScale: CGFloat = 1.0
156→  @State private var appearOpacity: CGFloat = 0
157→  @State private var panelSize: CGSize = CGSize(width: 200, height: 100)
158→  @State private var animationGeneration: Int = 0
159→
160→  private var currentWidth: CGFloat {
161→    let base = expanded ? panelSize.width : buttonSize
162→    return base * shrinkScale
163→  }
164→
165→  private var currentHeight: CGFloat {
166→    let base = expanded ? panelSize.height : buttonSize
167→    return base * shrinkScale
168→  }
169→
170→  private var currentCornerRadius: CGFloat {
171→    expanded ? 20 : (buttonSize * shrinkScale) / 2
172→  }
173→
174→  var body: some View {
175→    GeometryReader { _ in
176→      ZStack {
177→        if isVisible || expanded {
178→          anchoredLayout
179→            .opacity(appearOpacity)
180→            .frame(maxWidth: .infinity, maxHeight: .infinity)
181→            .contentShape(Rectangle())
182→            .onTapGesture {
183→              onDismiss()
184→            }
185→        }
186→
187→        // Hidden measurement view to capture panel natural size
188→        optionsList
189→          .fixedSize()
190→          .hidden()
191→          .onGeometryChange(for: CGSize.self) { proxy in
192→            proxy.size
193→          } action: { newSize in
194→            panelSize = newSize
195→          }
196→      }
197→    }
198→    .ignoresSafeArea()
199→    .onChange(of: isVisible) { _, newValue in
200→      // Generation counter cancels stale Phase 2 callbacks on rapid open/dismiss.
201→      // The dismiss branch must reset shrinkScale to 1.0 to handle the case where
202→      // Phase 1 set it to 0.8 but Phase 2 was cancelled by the guard.
203→      animationGeneration += 1
204→      let currentGeneration = animationGeneration
205→      if newValue {
206→        // Fade in the morph circle to match the React button fade-out
207→        appearOpacity = 0
208→        withAnimation(.spring(response: 0.25, dampingFraction: 0.9)) {
209→          appearOpacity = 1
210→        }
211→        // Phase 1: Shrink the button circle to 80%
212→        withAnimation(.spring(duration: 0.1)) {
213→          shrinkScale = 0.8
214→        }
215→        // Phase 2: Expand to panel size
216→        DispatchQueue.main.asyncAfter(deadline: .now() + 0.08) {
217→          guard animationGeneration == currentGeneration else { return }
218→          withAnimation(.spring(duration: 0.35, bounce: 0.3)) {
219→            expanded = true
220→            shrinkScale = 1.0
221→          }
222→        }
223→      } else {
224→        // Reverse: collapse to circle in one spring
225→        withAnimation(.spring(duration: 0.3, bounce: 0.1)) {
226→          expanded = false
227→          shrinkScale = 1.0
228→          appearOpacity = 0
229→        }
230→      }
231→    }
232→  }
233→
234→  private var morphContent: some View {
235→    ZStack {
236→      // Expanded content (options list)
237→      optionsList
238→        .fixedSize()
239→        .opacity(expanded ? 1 : 0)
240→    }
241→    .frame(width: currentWidth, height: currentHeight)
242→  }
243→
244→  @ViewBuilder
245→  private var morphingContainer: some View {
246→    if #available(iOS 26.0, *) {
247→      morphContent
248→        .glassEffect(.regular, in: RoundedRectangle(cornerRadius: currentCornerRadius))
249→    } else {
